using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type" in 9.0.
        // Preserve existing property name for backward compat with existing documents.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: Id format changed from "EntityType|Key" to just "Key" in 9.0.
        // Preserve existing id format for backward compat with existing documents.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .ToJsonProperty("id")
            .HasValueGenerator<LegacyIdValueGenerator>();

        // Breaking change 3: HasIndex() now throws for Cosmos in 9.0 (indexes are managed by Cosmos).
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);

        // Breaking change 4: Sync I/O now throws by default in 9.0.
        // See SyncJob.cs for the async migration.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

// Value generator that preserves the legacy "Discriminator|Key" id format
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;
class LegacyIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"{entry.Metadata.ShortName()}|{Guid.NewGuid()}";
}

